mapper.select:
SELECT id, user_id, title, created_at, updated_at
FROM ai_chat_sessions
WHERE id = #{id}

SELECT id, user_id, title, created_at, updated_at
FROM ai_chat_sessions
WHERE user_id = #{userId}
ORDER BY updated_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM ai_chat_sessions
WHERE user_id = #{userId}

mapper.update:
